import { useState, useEffect, useRef } from "react";

// ─── IslamicFamily Brand System ───
const B = {
  green: "#275D43",
  brown: "#E09964",
  mist: "#FAFAF2",
  black: "#353535",
  red: "#BB2D37",
  greenLight: "#275D4318",
  brownLight: "#E0996420",
  greenMid: "#275D4340",
  greenDark: "#1e4a35",
};

// ─── Embedded Images (base64, numbered to match upload order) ───
const IMAGES = {
  img1: "data:image/webp;base64,",
  img2: "data:image/png;base64,",
  img3: "data:image/png;base64,",
  img4: "data:image/png;base64,",
  img5: "data:image/png;base64,",
};


// ─── Scroll-reveal hook ───
function useReveal(threshold = 0.12) {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const obs = new IntersectionObserver(
      ([e]) => { if (e.isIntersecting) { setVisible(true); obs.unobserve(el); } },
      { threshold }
    );
    obs.observe(el);
    return () => obs.disconnect();
  }, [threshold]);
  return [ref, visible];
}

// ─── Animated wrapper ───
function Reveal({ children, delay = 0, direction = "up", style = {} }) {
  const [ref, visible] = useReveal();
  const t = { up: "translateY(48px)", left: "translateX(48px)", none: "none" };
  return (
    <div ref={ref} style={{
      opacity: visible ? 1 : 0,
      transform: visible ? "none" : (t[direction] || t.up),
      transition: `opacity 0.9s cubic-bezier(0.22,1,0.36,1) ${delay}s, transform 0.9s cubic-bezier(0.22,1,0.36,1) ${delay}s`,
      ...style,
    }}>{children}</div>
  );
}

// ─── Progress bar ───
function ProgressBar() {
  const [p, setP] = useState(0);
  useEffect(() => {
    const f = () => { const h = document.documentElement.scrollHeight - window.innerHeight; setP(h > 0 ? (window.scrollY / h) * 100 : 0); };
    window.addEventListener("scroll", f, { passive: true });
    return () => window.removeEventListener("scroll", f);
  }, []);
  return (
    <div style={{ position: "fixed", top: 0, left: 0, width: "100%", height: 3, zIndex: 999 }}>
      <div style={{ height: "100%", width: `${p}%`, background: `linear-gradient(90deg, ${B.green}, ${B.brown})`, transition: "width 0.1s linear" }} />
    </div>
  );
}

// ─── Floating TOC Menu ───
function TocMenu() {
  const [open, setOpen] = useState(false);
  const sections = [
    { id: "sec-compass", label: "The Compass" },
    { id: "sec-problem", label: "The Problem" },
    { id: "sec-alternative", label: "The Alternative" },
    { id: "sec-principles", label: "Guiding Principles" },
    { id: "sec-method", label: "The Method" },
    { id: "sec-transform", label: "Transform" },
    { id: "sec-conclusion", label: "Looking Forward" },
    { id: "sec-references", label: "References" },
  ];
  const scrollTo = (id) => {
    const el = document.getElementById(id);
    if (el) el.scrollIntoView({ behavior: "smooth", block: "start" });
    setOpen(false);
  };
  return (
    <>
      {/* Hamburger button */}
      <button
        onClick={() => setOpen(!open)}
        aria-label="Table of contents"
        style={{
          position: "fixed", top: 20, right: 20, zIndex: 1001,
          width: 44, height: 44, borderRadius: "50%",
          background: open ? B.green : B.mist,
          border: `1.5px solid ${B.greenMid}`,
          cursor: "pointer", display: "flex", flexDirection: "column",
          alignItems: "center", justifyContent: "center", gap: 4,
          transition: "all 0.3s ease",
          boxShadow: "0 2px 12px rgba(0,0,0,0.08)",
        }}
      >
        {[0, 1, 2].map(i => (
          <span key={i} style={{
            display: "block", width: 16, height: 1.5, borderRadius: 1,
            background: open ? B.mist : B.green,
            transition: "all 0.3s ease",
            transform: open
              ? (i === 0 ? "rotate(45deg) translate(3.5px, 3.5px)" : i === 1 ? "scaleX(0)" : "rotate(-45deg) translate(3.5px, -3.5px)")
              : "none",
            opacity: open && i === 1 ? 0 : 1,
          }} />
        ))}
      </button>

      {/* Panel */}
      <div style={{
        position: "fixed", top: 0, right: 0, zIndex: 1000,
        width: open ? 280 : 0, height: "100vh",
        background: B.mist, borderLeft: `1px solid ${B.greenMid}`,
        overflow: "hidden", transition: "width 0.35s cubic-bezier(0.22,1,0.36,1)",
        boxShadow: open ? "-4px 0 24px rgba(0,0,0,0.06)" : "none",
      }}>
        <nav style={{
          padding: "80px 32px 40px", width: 280, opacity: open ? 1 : 0,
          transition: "opacity 0.3s ease 0.15s",
        }}>
          <div style={{
            fontFamily: "'Alegreya Sans', sans-serif", fontSize: 11, letterSpacing: "0.2em",
            textTransform: "uppercase", color: B.green, marginBottom: 28, fontWeight: 500,
          }}>Contents</div>
          {sections.map((s, i) => (
            <button
              key={s.id}
              onClick={() => scrollTo(s.id)}
              style={{
                display: "block", width: "100%", textAlign: "left", background: "none",
                border: "none", cursor: "pointer", padding: "10px 0",
                borderBottom: i < sections.length - 1 ? `1px solid ${B.greenLight}` : "none",
                fontFamily: "'Alegreya', Georgia, serif", fontSize: 16, color: B.black,
                opacity: 0.75, transition: "opacity 0.2s",
              }}
              onMouseEnter={e => e.currentTarget.style.opacity = "1"}
              onMouseLeave={e => e.currentTarget.style.opacity = "0.75"}
            >
              <span style={{ fontSize: 10, color: B.green, marginRight: 10, opacity: 0.5 }}>✸</span>
              {s.label}
            </button>
          ))}
        </nav>
      </div>

      {/* Overlay */}
      {open && (
        <div
          onClick={() => setOpen(false)}
          style={{
            position: "fixed", top: 0, left: 0, right: 0, bottom: 0,
            zIndex: 999, background: "rgba(53,53,53,0.15)",
            transition: "opacity 0.3s ease",
          }}
        />
      )}
    </>
  );
}

// ─── Divider ───
